bool areConsecutive(vector<int>& arr, int n) {
    if (n < 1)
        return false;
    // Find minimum and maximum elements in the array
    int Min = *min_element(arr.begin(), arr.end());
    int Max = *max_element(arr.begin(), arr.end());
    // Check if array elements could be consecutive numbers
    if (Max - Min + 1 == n) {
        vector<bool> visited(n, false);
        for (int i = 0; i < n; i++) {
            int index = arr[i] - Min;
            // If already visited, array does not consist of consecutive distinct numbers
            if (visited[index])
                return false;
            visited[index] = true;
        }
        return true;
    }
    return false;
}

