bool canRepresentBST(const std::vector<int>& pre, int n) {
    std::vector<int> s;
    int root = INT_MIN; // equivalent to -2147483648
    for (int i = 0; i < n; i++) {
        // If we find a node who is on the right side and smaller than root, return false
        if (pre[i] < root) {
            return false;
        }
        // Nodes in stack that are smaller than the current pre[i] are no longer the root,
        // update the root to the last such node.
        while (!s.empty() && s.back() < pre[i]) {
            root = s.back();
            s.pop_back();
        }
        s.push_back(pre[i]);
    }
    return true;
}

