bool checkDivisibility(string num) {
    int length = num.size();
    if (length == 1 && num[0] == '0') {
        return true;
    }
    // Adjust the string length to be a multiple of 3 by appending zeros at the end
    if (length % 3 == 1) {
        num.append("00");
        length += 2;
    } else if (length % 3 == 2) {
        num.append("0");
        length += 1;
    }
    long long total = 0;
    int p = 1;
    for (int i = length - 1; i >= 0; i -= 3) {
        int group = 0;
        // Extract the ones digit
        group += (num[i] - '0');
        // Extract the tens digit
        group += (num[i - 1] - '0') * 10;
        // Extract the hundreds digit
        group += (num[i - 2] - '0') * 100;
        total += group * p;
        p *= -1;
    }
    // Taking absolute value of total
    if (total < 0)
        total = -total;
    return (total % 13 == 0);
}

