bool checkReverse(const vector<int>& arr, int n) {
    if (n == 1) {
        return true;
    }
    int i = 1;
    // Find the point where the array stops strictly increasing
    for (i = 1; i < n; i++) {
        if (arr[i - 1] >= arr[i]) {
            break;
        } else {
            if (i == n) {  // This branch will never be hit because i<n in the for loop.
                return true;
            }
        }
    }
    int j = i;
    i++;  // i now corresponds to one index past the breaking point in the for loop
    // Process the strictly decreasing part starting at index j.
    // Added boundary check (j < n) to prevent accessing beyond arr.
    while (j < n && arr[j] < arr[j - 1]) {
        if (i > 1 && arr[j] < arr[i - 2]) {
            return false;
        }
        j++;
    }
    if (j == n) {
        return true;
    }
    int k = j;
    if (arr[k] < arr[i - 1]) {
        return false;
    }
    // Check the rest of the array to ensure it isn't decreasing.
    while (k < n && k > 1) {
        if (arr[k] < arr[k - 1]) {
            return false;
        }
        k++;
    }
    return true;
}

