        return false;
    int l = str2.length();
    // Create the anticlockwise rotated string:
    // anticlock_rot = last two characters + first (l-2) characters
    string anticlock_rot = str2.substr(l - 2) + str2.substr(0, l - 2);
    // Create the clockwise rotated string:
    // clock_rot = from index 2 to end + first two characters
    string clock_rot = str2.substr(2) + str2.substr(0, 2);
