int isPossible(int n, int index, int modulo, int M, const vector<int>& arr, vector<vector<int>>& dp) {
    // Normalize modulo value
    modulo = ((modulo % M) + M) % M;
    // Base case: if we reached the end of the array, check if modulo equals 0
    if (index == n) {
        return (modulo == 0) ? 1 : 0;
    }
    // Use memoization: if already computed, return the stored value.
    if (dp[index][modulo] != -1) {
        return dp[index][modulo];
    }
    // Recursively check the possibility with adding or subtracting the current element.
    int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
    int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
    int res = (placeAdd || placeMinus) ? 1 : 0;
    // Store the computed result in dp.
    dp[index][modulo] = res;
    return res;
}

