string decimalToBinary(double num, int k_prec) {
    string binary = "";
    int Integral = static_cast<int>(num);
    double fractional = num - Integral;
    // Process integer part
    while (Integral > 0) {
        int rem = Integral % 2;
        binary += char('0' + rem);
        Integral /= 2;
    }
    // If the number is zero, ensure we have a '0' before the decimal point.
    if (binary.empty()) {
        binary = "0";
    } else {
        // Reverse the bits collected to get the correct order.
        reverse(binary.begin(), binary.end());
    }
    // Append the decimal point.
    binary += '.';
    // Process fractional part up to k_prec digits.
    while (k_prec > 0) {
        fractional *= 2;
        int fract_bit = static_cast<int>(fractional);
        if (fract_bit == 1) {
            fractional -= fract_bit;
            binary += '1';
        } else {
            binary += '0';
        }
        k_prec--;
    }
    return binary;
}

