long long countStrings(int n, int k) {
    // Create a 3-dimensional dp vector
    vector<vector<vector<long long>>> dp(n + 1, vector<vector<long long>>(k + 1, vector<long long>(2, 0)));
    // Base case initialization
    dp[1][0][0] = 1;
    dp[1][0][1] = 1;
    // Fill the dp table for lengths from 2 to n
    for (int i = 2; i <= n; i++) {
        for (int j = 0; j <= k; j++) {
            if (j >= i) {
                break;
            }
            // Transition for the case when the current ending bit is 0
            dp[i][j][0] = dp[i - 1][j][0] + dp[i - 1][j][1];
            // Transition for the case when the current ending bit is 1:
            // first, continue by appending 1 after a 0
            dp[i][j][1] = dp[i - 1][j][0];
            // second, if possible, continue by appending 1 after a 1
            if (j >= 1) {
                dp[i][j][1] += dp[i - 1][j - 1][1];
            }
        }
    }
    // The answer is the sum for strings ending with 0 or 1 at length n with k occurrences
    return dp[n][k][0] + dp[n][k][1];
}
