int findSubsequenceCount(const string &S, const string &T) {
    int m = T.size();
    int n = S.size();
    if (m > n) {
        return 0;
    }
    // Create a matrix with (m+1) x (n+1) initialized to 0.
    vector<vector<int>> mat(m + 1, vector<int>(n + 1, 0));
    // Set mat[0][j] = 1 for all j (empty T is a subsequence of any prefix of S)
    for (int j = 0; j <= n; j++) {
        mat[0][j] = 1;
    }
    // For i>=1, mat[i][0] is already 0 (no non-empty T can be a subsequence of an empty S)
    // Populate the matrix using the recurrence:
    // If the current characters don't match, we can only skip the current character in S.
    // Otherwise, we can either skip or consider the match.
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (T[i - 1] != S[j - 1]) {
                mat[i][j] = mat[i][j - 1];
            } else {
                mat[i][j] = mat[i][j - 1] + mat[i - 1][j - 1];
            }
        }
    }
    return mat[m][n];
}

