int sortedCount(const vector<vector<int>>& mat, int r, int c) {
    int result = 0;
    // Check for rows strictly increasing from left to right.
    for (int i = 0; i < r; i++) {
        int j;
        for (j = 0; j < c - 1; j++) {
            if (mat[i][j + 1] <= mat[i][j])
                break;
        }
        // If j reached c-2, it means we never broke early,
        // so the row is strictly increasing.
        if (j == c - 1 - 1)
            result++;
    }
    // Check for rows strictly decreasing from right to left.
    for (int i = 0; i < r; i++) {
        int j;
        // Start from the end and go backwards.
        for (j = c - 1; j > 0; j--) {
            if (mat[i][j - 1] <= mat[i][j])
                break;
        }
        // Only count if there is more than one element and we reached the start.
        if (c > 1 && j == 1)
            result++;
    }
    return result;
}

