string decode(const string &Str) {
    vector<int> integerStack;
    vector<char> stringStack;
    string temp = "";
    string result = "";
    int n = Str.size();
    // Use an index that can be manually modified
    for (int i = 0; i < n; i++) {
        int count = 0;
        // If current char is a digit, build the full number
        if (Str[i] >= '0' && Str[i] <= '9') {
            while (i < n && Str[i] >= '0' && Str[i] <= '9') {
                count = count * 10 + (Str[i] - '0');
                i++;
            }
            // Adjust index as the for loop will also increment it
            i--;
            integerStack.push_back(count);
        }
        else if (Str[i] == ']') {
            temp = "";
            count = 0;
            if (!integerStack.empty()) {
                count = integerStack.back();
                integerStack.pop_back();
            }
            // Build the substring inside the bracket
            while (!stringStack.empty() && stringStack.back() != '[') {
                char ch = stringStack.back();
                temp = ch + temp;
                stringStack.pop_back();
            }
            // Remove the '[' from the stack
            if (!stringStack.empty() && stringStack.back() == '[') {
                stringStack.pop_back();
            }
            // Repeat the substring 'count' times and push the result back on the stack
            result = "";
            for (int j = 0; j < count; j++) {
                result += temp;
            }
            for (int j = 0; j < result.size(); j++) {
                stringStack.push_back(result[j]);
            }
            result = "";
        }
        else if (Str[i] == '[') {
            // Check if previous character was a digit
            if (i - 1 >= 0 && Str[i - 1] >= '0' && Str[i - 1] <= '9')
                stringStack.push_back(Str[i]);
            else {
                stringStack.push_back(Str[i]);
                integerStack.push_back(1);
            }
        }
        else {
            // For alphabets or other characters, just push to stringStack
            stringStack.push_back(Str[i]);
        }
    }
    // Build the final result from the stringStack
    result = "";
    while (!stringStack.empty()) {
        result = stringStack.back() + result;
        stringStack.pop_back();
    }
    return result;
}
