int findWays(int m, int n, int x) {
    // Create a table with (n+1) rows and (x+1) columns initialized to 0.
    std::vector<std::vector<int>> table(n + 1, std::vector<int>(x + 1, 0));
    // Initialize the base case:
    // For one part (i.e. table[1]), set table[1][j] = 1 for j = 1 up to min(m, x)
    for (int j = 1; j <= std::min(m, x); j++) {
        table[1][j] = 1;
