            // In Python, range(1, min(m+1, j)) means k from 1 up to (but not including) min(m+1, j).
            int upperBound = std::min(m + 1, j);
            for (int k = 1; k < upperBound; k++) {
                table[i][j] += table[i - 1][j - k];
