    // Prepare a table to store best baby steps (using a vector of size m initialized with 0)
    std::vector<int> value(m, 0);
    // Compute giant steps and store the step index for each value if not already stored
    long long cur = an;
    for (int i = 1; i <= n; i++) {
        if (value[cur] == 0) {
            value[cur] = i;
        }
        cur = (cur * an) % m;
    }
    // Solve for the discrete logarithm by iterating baby steps
    cur = b;
    for (int i = 0; i <= n; i++) {
        if (value[cur] > 0) {
            int ans = value[cur] * n - i;
            if (ans < m) {
                return ans;
            }
        }
        cur = (cur * a) % m;
    }
    // If no solution is found, return -1
    return -1;
}

