std::string longDivision(const std::string &number, int divisor) {
    std::string ans = "";
    int idx = 0;
    int n = number.size();
    int temp = number[idx] - '0';
    // Build up temp until it is greater than or equal to divisor
    while (temp < divisor && idx < n - 1) {
        idx++;
        temp = temp * 10 + (number[idx] - '0');
    }
    // Process all digits except the last one in the string
    while (idx < n - 1) {
        int quotientDigit = temp / divisor;
        ans.push_back('0' + quotientDigit);
        temp = (temp % divisor) * 10 + (number[++idx] - '0');
    }
    // Append the final quotient digit
    ans.push_back('0' + (temp / divisor));
    if (ans.empty())
        return "0";
    return ans;
}

