int eggDrop(int n, int k) {
    // Create a 2D vector to store results of subproblems
    vector<vector<int>> eggFloor(n + 1, vector<int>(k + 1, 0));
    // We need one trial for one floor and 0 trials for 0 floors
    for (int i = 1; i <= n; i++) {
        eggFloor[i][0] = 0;
        eggFloor[i][1] = 1;
    }
    // We always need j trials for one egg and j floors.
    for (int j = 1; j <= k; j++) {
        eggFloor[1][j] = j;
    }
    // Fill the rest of the entries in table using optimal substructure property
    for (int i = 2; i <= n; i++) {
        for (int j = 2; j <= k; j++) {
            eggFloor[i][j] = INT_MAX;
            for (int x = 1; x <= j; x++) {
                // Calculate number of trials needed in worst case and choose minimum among all x
                int res = 1 + max(eggFloor[i - 1][x - 1], eggFloor[i][j - x]);
                eggFloor[i][j] = min(eggFloor[i][j], res);
            }
        }
    }
    // eggFloor[n][k] holds the result
    return eggFloor[n][k];
}

