int minPalPartion(const string &str) {
    int n = str.length();
    // Create a 2D vector for storing minimum cuts
    vector<vector<int>> C(n, vector<int>(n, 0));
    // Create a 2D vector to check for palindrome substrings
    vector<vector<bool>> P(n, vector<bool>(n, false));
    // Every single letter is a palindrome.
    for (int i = 0; i < n; i++) {
        P[i][i] = true;
        C[i][i] = 0;
    }
    // L is the substring length.
    for (int L = 2; L <= n; L++) {
        for (int i = 0; i <= n - L; i++) {
            int j = i + L - 1;  // Ending index of substring of length L
            if (L == 2)
                P[i][j] = (str[i] == str[j]);
            else
                P[i][j] = (str[i] == str[j] && P[i + 1][j - 1]);
            // If substring str[i...j] is a palindrome, no cuts are needed.
            if (P[i][j])
                C[i][j] = 0;
            else {
                C[i][j] = 100000000;  // A large number essentially "infinity"
                // Try making a cut at every possible location to find the minimum cuts.
                for (int k = i; k < j; k++) {
                    C[i][j] = min(C[i][j], C[i][k] + C[k + 1][j] + 1);
                }
            }
        }
    }
    return C[0][n - 1];
}

