long long countParenth(const vector<char>& symb, const vector<char>& oper, int n) {
    // T[i][j] stores the number of ways to parenthesize symb[i..j] such that the expression is true
    // F[i][j] stores the number of ways to parenthesize symb[i..j] such that the expression is false
    vector<vector<long long>> T(n, vector<long long>(n, 0));
    vector<vector<long long>> F(n, vector<long long>(n, 0));
    // Initialize the tables for single symbols
    for (int i = 0; i < n; i++) {
        if (symb[i] == 'T') {
            T[i][i] = 1;
            F[i][i] = 0;
        } else { // symb[i] == 'F'
            T[i][i] = 0;
            F[i][i] = 1;
        }
    }
    // gap represents the distance between i and j
    for (int gap = 1; gap < n; gap++) {
        for (int i = 0, j = gap; j < n; i++, j++) {
            T[i][j] = 0;
            F[i][j] = 0;
            // iterate over all possible splits
            for (int g = 0; g < gap; g++) {
                int k = i + g;
                long long tik = T[i][k] + F[i][k];      // total ways for left side
                long long tkj = T[k + 1][j] + F[k + 1][j];  // total ways for right side
                if (oper[k] == '&') {
                    T[i][j] += T[i][k] * T[k + 1][j];
                    F[i][j] += (tik * tkj - T[i][k] * T[k + 1][j]);
                }
                else if (oper[k] == '|') {
                    F[i][j] += F[i][k] * F[k + 1][j];
                    T[i][j] += (tik * tkj - F[i][k] * F[k + 1][j]);
                }
                else if (oper[k] == '^') {
                    T[i][j] += (F[i][k] * T[k + 1][j] + T[i][k] * F[k + 1][j]);
                    F[i][j] += (T[i][k] * T[k + 1][j] + F[i][k] * F[k + 1][j]);
                }
            }
        }
    }
    return T[0][n - 1];
}

