int MatrixChainOrder(int p[], int i, int j) {
    if (i == j)
        return 0;
    int minCost = numeric_limits<int>::max();
    // Try placing parenthesis at different locations between i and j
    for (int k = i; k < j; k++) {
        int count = MatrixChainOrder(p, i, k) +
