bool isSubsetSum(const vector<int>& set, int n, int sum) {
    // Create a 2D vector "subset" with dimensions (n+1) x (sum+1)
    vector<vector<bool>> subset(n + 1, vector<bool>(sum + 1, false));
    // If sum is 0, answer is true for any set of elements.
    for (int i = 0; i <= n; i++) {
        subset[i][0] = true;
    }
    // With 0 elements, no positive sum is possible.
    for (int j = 1; j <= sum; j++) {
        subset[0][j] = false;
    }
    // Fill the subset table in bottom-up manner.
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= sum; j++) {
            if (j < set[i - 1]) {
                // Cannot include the element set[i-1]
                subset[i][j] = subset[i - 1][j];
            } else {
                // Check if sum can be obtained by any of:
                // (i) including the element set[i-1]
                // (ii) excluding the element set[i-1]
                subset[i][j] = subset[i - 1][j] || subset[i - 1][j - set[i - 1]];
            }
        }
    }
    return subset[n][sum];
}

