int maxHamming(const std::vector<int>& arr, int n) {
    // Create brr array with 2*n elements (in Python code it uses 2*n+1, but the extra element isn’t used)
    std::vector<int> brr(2 * n);
    // First half: copy arr into brr[0 ... n-1]
    for (int i = 0; i < n; i++) {
        brr[i] = arr[i];
    }
    // Second half: append another copy of arr into brr[n ... 2*n-1]
    for (int i = 0; i < n; i++) {
        brr[n + i] = arr[i];
    }
    int maxHam = 0;
    // Compute the Hamming distance for every rotation starting from 1 to n-1
    for (int i = 1; i < n; i++) {
        int currHam = 0;
        int k = 0;
        for (int j = i; j < i + n; j++) {
            if (brr[j] != arr[k]) {
                currHam++;
            }
            k++;
        }
        // If maximum possible Hamming distance is achieved, return immediately.
        if (currHam == n)
            return n;
        maxHam = std::max(maxHam, currHam);
    }
    return maxHam;
}

