int findMaxAverage(const vector<int>& arr, int n, int k) {
    if (k > n)
        return -1;
    // Create cumulative sum array
    vector<int> csum(n, 0);
    csum[0] = arr[0];
    for (int i = 1; i < n; i++) {
        csum[i] = csum[i - 1] + arr[i];
    }
    // Initialize max_sum with the sum of first k elements
    int max_sum = csum[k - 1];
    int max_end = k - 1;
    // Slide the window through the array
    for (int i = k; i < n; i++) {
        int curr_sum = csum[i] - csum[i - k];
        if (curr_sum > max_sum) {
            max_sum = curr_sum;
            max_end = i;
        }
    }
    // Return the starting index of subarray with maximum average
    return max_end - k + 1;
}

