int binaryMedian(const vector<vector<int>> &matrix, int r, int c) {
    // Find the minimum element (first element of first row) and the maximum element (last element of last row) among all rows.
    int mi = INT_MAX;
    int mx = INT_MIN;
    for (int i = 0; i < r; i++) {
        mi = min(mi, matrix[i][0]);
        mx = max(mx, matrix[i][c - 1]);
    }
    // Calculate desired position (median position)
    int desired = (r * c + 1) / 2;
    // Binary search between min and max
    while (mi < mx) {
        int mid = mi + (mx - mi) / 2;
        // Count number of elements less than or equal to mid
        int count = 0;
        for (int i = 0; i < r; i++) {
            // upper_bound returns iterator to first element greater than mid; subtracting begin() gives the count of elements <= mid.
            count += upper_bound(matrix[i].begin(), matrix[i].end(), mid) - matrix[i].begin();
        }
        // Adjust search range based on count
        if (count < desired)
            mi = mid + 1;
        else
            mx = mid;
    }
    cout << "Median is " << mi << endl;
    return mi;
}
