int count(const std::string &a, const std::string &b) {
    int m = a.size();
    int n = b.size();
    // Initialize a 2D vector (lookup) with dimensions (m+1) x (n+1) filled with zeros.
    std::vector<std::vector<int>> lookup(m + 1, std::vector<int>(n + 1, 0));
    // When string a is empty, there are no subsequences of b (except the empty subsequence, but we assume pattern b is non-empty)
    // so initialize lookup[0][j] = 0 for all j.
    for (int j = 0; j <= n; j++) {
        lookup[0][j] = 0;
    }
    // An empty string b is a subsequence of any prefix of a exactly 1 time.
    for (int i = 0; i <= m; i++) {
        lookup[i][0] = 1;
    }
    // Fill the DP table.
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (a[i - 1] == b[j - 1]) {
                // If the characters match, add both possibilities:
                // 1. a[i-1] is used to match b[j-1]
                // 2. a[i-1] is not used 
                lookup[i][j] = lookup[i - 1][j - 1] + lookup[i - 1][j];
            } else {
                // If characters do not match, we can only skip a[i-1]
                lookup[i][j] = lookup[i - 1][j];
            }
        }
    }
    return lookup[m][n];
}

