    // Initialize a 2D vector with dimensions (n+1) x (n+1) and fill with 0.
    vector<vector<int>> C(n + 1, vector<int>(n + 1, 0));
    // Build Pascal's triangle.
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= min(i, n); j++) {
            if (j == 0 || j == i) {
                C[i][j] = 1;
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
