long long sumofoddFactors(long long n) {
    long long res = 1;
    // Remove all factors of 2, because we are interested in odd factors only.
    while(n % 2 == 0) {
        n /= 2;
    }
    // Check for potential odd factors.
    // We loop from 3 to sqrt(n) (plus 1, to mimic the Python range behavior).
    for (long long i = 3; i < static_cast<long long>(std::sqrt(n)) + 1; i++) {
        long long curr_sum = 1;
        long long curr_term = 1;
        // While i divides n, accumulate the terms (i^0 + i^1 + ... + i^count).
        while(n % i == 0) {
            n /= i;
            curr_term *= i;
            curr_sum += curr_term;
        }
        res *= curr_sum;
    }
    // If n is > 1, then it is a prime factor greater than the square root,
    // so multiply the result by (1 + n) for that prime factor.
    if(n >= 2)
        res *= (1 + n);
    return res;
}

