int pairsInSortedRotated(const vector<int>& arr, int n, int x) {
    int i;
    // Find the pivot point where the next element is smaller than the current one.
    // We use modulo for safe indexing at the boundary.
    for (i = 0; i < n; i++) {
        if (arr[i] > arr[(i + 1) % n]) {
            break;
