    }
    // l is the index of the smallest element
    int l = (i + 1) % n;
    // r is the index of the largest element
    int r = i;
    int cnt = 0;
    // Process pairs until the two indices meet.
    while (l != r) {
        int sum = arr[l] + arr[r];
        if (sum == x) {
            cnt++;
            // If l and r are adjacent, then this is the last possible pair.
            if (l == (r - 1 + n) % n)
                return cnt;
            l = (l + 1) % n;
            r = (r - 1 + n) % n;
        }
        else if (sum < x) {
            l = (l + 1) % n;
        }
        else { // sum > x
            r = (r - 1 + n) % n;
        }
    }
    return cnt;
}

