// Gnome sort function: sorts the vector 'arr' in non-decreasing order.
std::vector<int> gnomeSort(std::vector<int>& arr, int n) {
    int index = 0;
    while (index < n) {
        if (index == 0) {
            index++;
        }
        // Since here index is at least 1, we compare with the previous element.
        if (arr[index] >= arr[index - 1]) {
            index++;
        } else {
            std::swap(arr[index], arr[index - 1]);
            index--;
        }
    }
    return arr;
}

