int kthLargestSum(vector<int>& arr, int n, int k) {
    // Build prefix sum array; using long long to avoid potential overflow
    vector<long long> prefix(n + 1, 0);
    prefix[0] = 0;
    if(n > 0)
        prefix[1] = arr[0];
    for (int i = 2; i <= n; i++) {
        prefix[i] = prefix[i - 1] + arr[i - 1];
    }
    // Min-heap to maintain the k largest subarray sums.
    priority_queue<long long, vector<long long>, greater<long long>> minHeap;
    // Iterate over all possible contiguous subarrays using prefix sums.
    for (int i = 1; i <= n; i++) {
        for (int j = i; j <= n; j++) {
            long long subSum = prefix[j] - prefix[i - 1];
            if (minHeap.size() < k) {
                minHeap.push(subSum);
            } else if (minHeap.top() < subSum) {
                minHeap.pop();
                minHeap.push(subSum);
            }
        }
    }
    // The kth largest sum is now at the top of the min-heap.
    return static_cast<int>(minHeap.top());
}

