int maxLength(const string &s, int n) {
    // Create a 2D dp vector initialized with 0's
    vector<vector<int>> dp(n, vector<int>(n, 0));
    // Base cases: Check for pairs "()" that are adjacent.
    for (int i = 0; i < n - 1; i++) {
        if (s[i] == '(' && s[i + 1] == ')') {
            dp[i][i + 1] = 2;
        }
    }
    // Fill dp table for substrings of length >= 3
    // l represents the end index difference j - i (starting from 2)
    for (int l = 2; l < n; l++) {
        int i = -1;
        for (int j = l; j < n; j++) {
            i++;
            // If the current substring can potentially form a valid pair by matching the outer parentheses,
            // add the length of the valid inside substring.
            if (s[i] == '(' && s[j] == ')') {
                dp[i][j] = 2 + dp[i + 1][j - 1];
            }
            // Try to split the substring into two parts and update dp[i][j] 
            // if combining the two parts gives a better solution.
            for (int k = i; k < j; k++) {
                dp[i][j] = max(dp[i][j], dp[i][k] + dp[k + 1][j]);
            }
        }
    }
    return dp[0][n - 1];
}
