int lenghtOfLongestAP(const vector<int>& set, int n) {
    if (n <= 2)
        return n;
    // Create a 2D vector initialized with 0
    vector<vector<int>> L(n, vector<int>(n, 0));
    int llap = 2;
    // Initialize the last column as 2 for all i
    for (int i = 0; i < n; i++)
        L[i][n - 1] = 2;
    // Consider every element set[j] as the second last element of AP
    for (int j = n - 2; j >= 1; j--) {
        int i = j - 1;
        int k = j + 1;
        while (i >= 0 && k <= n - 1) {
            if (set[i] + set[k] < 2 * set[j])
                k++;
            else if (set[i] + set[k] > 2 * set[j]) {
                L[i][j] = 2;
                i--;
            }
            else {
                // Found i, j, k that form an AP
                L[i][j] = L[j][k] + 1;
                llap = max(llap, L[i][j]);
                i--;
                k++;
            }
        }
        // If the loop was stopped, set remaining L[i][j] as 2
        while (i >= 0) {
            L[i][j] = 2;
            i--;
        }
    }
    return llap;
}

