string longestRepeatedSubSeq(const string &s) {
    int n = s.size();
    // Create a DP table with (n+1) x (n+1) elements initialized to 0.
    vector<vector<int>> dp(n + 1, vector<int>(n + 1, 0));
    // Fill the dp table similar to LCS (Longest Common Subsequence)
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            if (s[i - 1] == s[j - 1] && i != j) {
                dp[i][j] = 1 + dp[i - 1][j - 1];
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }
    // Reconstruct the repeated subsequence from the dp table
    string res = "";
    int i = n, j = n;
    while (i > 0 && j > 0) {
        if (dp[i][j] == dp[i - 1][j - 1] + 1) {
            res.push_back(s[i - 1]);
            i--;
            j--;
        } else if (dp[i][j] == dp[i - 1][j]) {
            i--;
        } else {
            j--;
        }
    }
    // The subsequence is built backwards, so reverse it.
    reverse(res.begin(), res.end());
    return res;
}

