                    dp[ind][val] = dp[ind - 1][val + arr[ind]];
                } else {
                    dp[ind][val] = 0;
                }
            }
        }
    }
    // Scan from maxLimit down to 0 to find the largest valid value.
    for (int val = maxLimit; val >= 0; --val) {
