int maxProfit(std::vector<int>& price, int n) {
    std::vector<int> profit(n, 0);
    // Initializing the maximum price as the last element in price
    int max_price = price[n - 1];
    // Fill profit[] in reverse order for potential sale values.
    // We start from n - 2 down to 1 (Python loop: range(n - 2, 0, -1))
    for (int i = n - 2; i > 0; i--) {
        if (price[i] > max_price) {
            max_price = price[i];
        }
        profit[i] = std::max(profit[i + 1], max_price - price[i]);
    }
    // Initializing the minimum price as the first element of price
    int min_price = price[0];
    // Calculate the maximum profit by combining the profits from both transactions.
    for (int i = 1; i < n; i++) {
        if (price[i] < min_price) {
            min_price = price[i];
        }
        profit[i] = std::max(profit[i - 1], profit[i] + (price[i] - min_price));
    }
    return profit[n - 1];
}

