int getMedian(int ar1[], int ar2[], int n) {
    int i = 0, j = 0;
    int m1 = -1, m2 = -1;
    int count = 0;
    // The following loop runs until count becomes n+1, thus ensuring m1 and m2 are at proper positions.
    while (count < n + 1) {
        count++;
        // If all elements of ar1 have been processed
        if (i == n) {
            m1 = m2;
            m2 = ar2[0];
            break;
        }
        // If all elements of ar2 have been processed
        else if (j == n) {
            m1 = m2;
            m2 = ar1[0];
            break;
        }
        // Pick the smaller element from ar1 or ar2 and update m1 and m2 accordingly
        if (ar1[i] < ar2[j]) {
            m1 = m2;
            m2 = ar1[i];
            i++;
        } else {
            m1 = m2;
            m2 = ar2[j];
            j++;
        }
    }
    return (m1 + m2) / 2;
}
