    // Define INF as a large number.
    const int INF = 1000000000;
    // Filter out items with valid costs, and record their corresponding weights.
    vector<int> val, wt;
    int size = 0;
    for (int i = 0; i < n; i++) {
        if (cost[i] != -1) {
            val.push_back(cost[i]);
            // weight is (index + 1)
            wt.push_back(i + 1);
            size++;
        }
    }
    // Update n to be the number of valid items.
    n = size;
    // Create a dynamic programming table with dimensions (n+1) x (W+1)
    vector<vector<int>> min_cost(n + 1, vector<int>(W + 1, 0));
    // Initialize the 0th row. For zero items, cost to achieve any positive weight is INF.
    for (int j = 0; j <= W; j++)
        min_cost[0][j] = INF;
    // With weight 0, cost is 0 for all items.
    for (int i = 1; i <= n; i++)
        min_cost[i][0] = 0;
    // Fill the dynamic programming table.
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= W; j++) {
            if (wt[i - 1] > j) {
                // Cannot include this item because its weight is more than j.
                min_cost[i][j] = min_cost[i - 1][j];
            } else {
                // Either do not take the item or take the item (if it fits).
                min_cost[i][j] = min(min_cost[i - 1][j], min_cost[i][j - wt[i - 1]] + val[i - 1]);
            }
        }
    }
    // If we couldn't form the weight W, return -1.
    if (min_cost[n][W] >= INF)
        return -1;
    else
        return min_cost[n][W];
}
