int minJumps(const vector<int>& arr, int n) {
    // Check if there are no elements or the first element is 0 (so no jumps possible)
    if (n == 0 || arr[0] == 0) {
        return numeric_limits<int>::max();  // This represents infinity.
    }
    // Create a vector to store the minimum number of jumps for each index.
    vector<int> jumps(n, numeric_limits<int>::max());
    jumps[0] = 0;  // Starting position requires 0 jumps.
    // Calculate minimum jumps required for each position.
    for (int i = 1; i < n; i++) {
        // Check all positions before i to see if i is reachable
        for (int j = 0; j < i; j++) {
            if (jumps[j] != numeric_limits<int>::max() && i <= j + arr[j]) {
                jumps[i] = min(jumps[i], jumps[j] + 1);
                break;  // Once found, no need to check earlier indices for a better jump count.
            }
        }
    }
    return jumps[n - 1];
}
