int minJumps(const vector<int>& arr, int n) {
    // Define an infinity value using the largest integer value available.
    const int INF = numeric_limits<int>::max();
    // Create a vector "jumps" of size n initialized to 0.
    vector<int> jumps(n, 0);
    // Traverse the array from the second last element down to the first.
    for (int i = n - 2; i >= 0; --i) {
        // If the current element is 0, you cannot move forward from here.
        if (arr[i] == 0) {
            jumps[i] = INF;
        }
        // If the current jump can reach or surpass the end, mark it as 1 jump.
        else if (arr[i] >= n - i - 1) {
            jumps[i] = 1;
        }
        // Otherwise, calculate the minimum number of jumps from the reachable range.
        else {
            int minVal = INF;
            // Only iterate through the indices that are reachable with a jump from the current position.
            for (int j = i + 1; j < n && j <= i + arr[i]; ++j) {
                if (jumps[j] < minVal) {
                    minVal = jumps[j];
                }
            }
            // If a valid jump sequence was found, add one; otherwise, leave it as INF.
            if (minVal != INF)
                jumps[i] = minVal + 1;
            else
                jumps[i] = INF;
        }
    }
    return jumps[0];
}
