int getMinSquares(int n) {
    // Initialize dp array with enough size and initial values.
    vector<int> dp(n + 1, 0);
    // Base cases
    if (n >= 0) dp[0] = 0;
    if (n >= 1) dp[1] = 1;
    if (n >= 2) dp[2] = 2;
    if (n >= 3) dp[3] = 3;
    // Fill dp array using the recurrence relation
    for (int i = 4; i <= n; i++) {
        dp[i] = i;  // maximum value is i (i times 1^2)
        // Iterate over all squares less than or equal to i
        for (int x = 1; x <= static_cast<int>(ceil(sqrt(i))); x++) {
            int temp = x * x;
            if (temp > i)
                break;
            else
                dp[i] = min(dp[i], 1 + dp[i - temp]);
        }
    }
    return dp[n];
}

