int minTimeForWritingChars(int N, int insertCost, int removeCost, int copyCost) {
    if (N == 0)
        return 0;
    if (N == 1)
        return insertCost;
    vector<int> dp(N + 1, 0);
    // Base case: dp[1] is implicitly computed when i = 1 in the loop.
    for (int i = 1; i <= N; i++) {
        if (i % 2 == 0) {
            dp[i] = min(dp[i - 1] + insertCost, dp[i / 2] + copyCost);
        } else {
            // When i is odd, we consider going to (i+1) and then removing one character.
            dp[i] = min(dp[i - 1] + insertCost, dp[(i + 1) / 2] + copyCost + removeCost);
        }
    }
    return dp[N];
}
