void segregateElements(std::vector<int>& arr) {
    int n = arr.size();
    std::vector<int> temp(n, 0);
    int j = 0;
    // Place non-negative elements first
    for (int i = 0; i < n; i++) {
        if (arr[i] >= 0) {
            temp[j] = arr[i];
            j++;
        }
