    // Then add the negative elements
    for (int i = 0; i < n; i++) {
        if (arr[i] < 0) {
            temp[j] = arr[i];
            j++;
        }
    }
    // Copy the arranged elements back to the original array
    for (int k = 0; k < n; k++) {
        arr[k] = temp[k];
    }
}

