long long countDivisibleSubseq(const string &s, int n) {
    int l = s.size();
    // Use a 2D DP table where dp[i][r] holds the count of subsequences
    // ending at or before index i that yield remainder r when divided by n.
    vector<vector<long long>> dp(l, vector<long long>(n, 0));
    // The subsequence consisting of only the first character.
    int digit = s[0] - '0';
    dp[0][digit % n]++;
    for (int i = 1; i < l; i++) {
        digit = s[i] - '0';
        // Count the subsequence that only contains the current character.
        dp[i][digit % n]++;
        // Extend all subsequences ending at i-1.
        for (int j = 0; j < n; j++) {
            // Carry forward the previous count (not using current digit).
            dp[i][j] += dp[i-1][j];
            // Append the current digit to each existing subsequence from i-1.
            dp[i][(j * 10 + digit) % n] += dp[i-1][j];
        }
    }
    return dp[l-1][0];
}

