double maxAverageOfPath(const vector<vector<int>> &cost, int N) {
    // Create a 2D dp vector with dimensions N x N initialized to 0
    vector<vector<int>> dp(N, vector<int>(N, 0));
    dp[0][0] = cost[0][0];
    // Fill the first column
    for (int i = 1; i < N; i++) {
        dp[i][0] = dp[i - 1][0] + cost[i][0];
    }
    // Fill the first row
    for (int j = 1; j < N; j++) {
        dp[0][j] = dp[0][j - 1] + cost[0][j];
    }
    // Fill the rest of the dp matrix
    for (int i = 1; i < N; i++) {
        for (int j = 1; j < N; j++) {
            dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
        }
    }
    // Return the average: total sum divided by (2*N - 1).
    return static_cast<double>(dp[N - 1][N - 1]) / (2 * N - 1);
}

