bool isPrime(int p) {
    // Compute the Mersenne number: 2^p - 1.
    // Note: This implementation assumes that p is small enough so that 2^p - 1 fits into unsigned long long.
    unsigned long long checkNumber = ((unsigned long long)1 << p) - 1;
    // Initialize nextval as 4 modulo checkNumber.
    unsigned long long nextval = 4 % checkNumber;
    // Perform the Lucas-Lehmer sequence iterations.
    for (int i = 1; i < p - 1; i++) {
        nextval = (nextval * nextval - 2) % checkNumber;
    }
    // Return true if the final value is 0, indicating that the number passes the Lucas-Lehmer test.
    return (nextval == 0);
}

