void antiSpiralTraversal(int m, int n, const vector<vector<int>>& a) {
    int k = 0, l = 0;
    vector<int> stk;
    // Traverse the matrix in spiral order.
    while (k <= m && l <= n) {
        // Traverse the top row from left to right.
        for (int i = l; i <= n; i++) {
            stk.push_back(a[k][i]);
        }
        k++;
        // Traverse the right column from top to bottom.
        for (int i = k; i <= m; i++) {
            stk.push_back(a[i][n]);
        }
        n--;
        // Traverse the bottom row from right to left, if any row remains.
        if (k <= m) {
            for (int i = n; i >= l; i--) {
                stk.push_back(a[m][i]);
            }
            m--;
        }
        // Traverse the left column from bottom to top, if any column remains.
        if (l <= n) {
            for (int i = m; i >= k; i--) {
                stk.push_back(a[i][l]);
            }
            l++;
        }
    }
    // Print the anti-spiral order by popping elements from the stack.
    while (!stk.empty()) {
        cout << stk.back() << " ";
        stk.pop_back();
    }
}

