int find_maximum(const vector<int>& a, int n, int k) {
    unordered_map<int, int> b;
    for (int i = 0; i < n; i++) {
        int x = a[i];
        int d = min(i + 1, n - i);
        // If x is not already in the map, insert it;
        // otherwise, update it with the minimum value found so far.
        if (b.find(x) == b.end())
            b[x] = d;
        else
            b[x] = min(d, b[x]);
    }
    int ans = numeric_limits<int>::max();
    for (int i = 0; i < n; i++) {
        int x = a[i];
        // Check if (k - x) exists as a key and x is not equal to (k - x)
        if (x != (k - x) && b.find(k - x) != b.end()) {
            ans = min(ans, max(b[x], b[k - x]));
        }
    }
    return ans;
}

