void rearrange(vector<int>& arr, int n) {
    int max_idx = n - 1;
    int min_idx = 0;
    int max_elem = arr[n - 1] + 1;
    // First pass: update each element with the encoded information.
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) {
            arr[i] += (arr[max_idx] % max_elem) * max_elem;
            max_idx--;
        } else {
            arr[i] += (arr[min_idx] % max_elem) * max_elem;
            min_idx++;
        }
    }
    // Second pass: decode the new values.
    for (int i = 0; i < n; i++) {
        arr[i] = arr[i] / max_elem;
    }
}
