    int series_index = 0;
    int result = 0;
    // Iterate over num from rightmost digit to leftmost.
    for (int i = num.size() - 1; i >= 0; --i) {
        int digit = num[i] - '0';
        result += digit * series[series_index];
        series_index = (series_index + 1) % 6;
        result %= 7;  // Keep result modulo 7
