std::string simplify(const std::string &Str) {
    int Len = Str.size();
    // We'll build the result gradually.
    std::string res;
    res.reserve(Len);
    // Stack to maintain the sign context; initialize with 0.
    std::vector<int> s;
    s.push_back(0);
    for (int i = 0; i < Len; i++) {
        char c = Str[i];
        if (c == '+') {
            if (s.back() == 1) {
                res.push_back('-');
            }
            if (s.back() == 0) {
                res.push_back('+');
            }
        } else if (c == '-') {
            if (s.back() == 1) {
                res.push_back('+');
            } else if (s.back() == 0) {
                res.push_back('-');
            }
        } else if (c == '(' && i > 0) {
            // Check the operator just before '(' to determine new sign context.
            if (Str[i - 1] == '-') {
                int x = (s.back() == 1) ? 0 : 1;
                s.push_back(x);
            } else if (Str[i - 1] == '+') {
                s.push_back(s.back());
            }
        } else if (c == ')') {
            // Close the current sign context.
            s.pop_back();
        } else {
            // For operands or other characters, simply add them.
            res.push_back(c);
        }
    }
    return res;
}

