int search(const vector<int>& arr, int l, int h, int key) {
    if (l > h) {
        return -1;
    }
    int mid = (l + h) / 2;
    if (arr[mid] == key) {
        return mid;
    }
    // Check if left part is sorted
    if (arr[l] <= arr[mid]) {
        // Check if the key lies in the left sorted part
        if (key >= arr[l] && key <= arr[mid]) {
            return search(arr, l, mid - 1, key);
        }
        // Otherwise search in the right half
        return search(arr, mid + 1, h, key);
    }
    // If left part isn't sorted, then right must be sorted
    if (key >= arr[mid] && key <= arr[h]) {
        return search(arr, mid + 1, h, key);
    }
    // Otherwise search in the left half
    return search(arr, l, mid - 1, key);
}

