int KnapSack(const vector<int>& val, const vector<int>& wt, int n, int W) {
    // Create a 2 x (W+1) DP matrix initialized to 0
    vector<vector<int>> mat(2, vector<int>(W + 1, 0));
    int i = 0;
    while (i < n) {
        int j = 0;
        if (i % 2 == 0) {
            // Use mat[0] as the previous row and update mat[1]
            while (j < W) {
                j++;
                // Check if the current weight can be added and ensure index bounds
                if (wt[i] <= j && (j - wt[i]) < W) 
                    mat[1][j] = max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                else
                    mat[1][j] = mat[0][j];
            }
        } else {
            // Use mat[1] as the previous row and update mat[0]
            while (j < W) {
                j++;
                if (wt[i] <= j && (j - wt[i]) < W)
                    mat[0][j] = max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                else
                    mat[0][j] = mat[1][j];
            }
        }
        i++;
    }
    // Return the result from the appropriate row depending on n's parity
    if (n % 2 == 0)
        return mat[0][W];
    else
        return mat[1][W];
}

