int gcd(int a, int b) {
    if (a == 0)
        return b;
    if (b == 0)
        return a;
    int k = 0;
    // Remove common factors of 2 from a and b
    while (((a | b) & 1) == 0) {
        a = a >> 1;
        b = b >> 1;
        k++;
    }
    // Remove remaining factors of 2 from a
    while ((a & 1) == 0) {
        a = a >> 1;
    }
    while (b != 0) {
        // Remove factors of 2 from b
        while ((b & 1) == 0) {
            b = b >> 1;
        }
        // Swap if necessary so that a <= b
        if (a > b) {
            int temp = a;
            a = b;
            b = temp;
        }
        // Subtract a from b to get the difference
        b = b - a;
    }
    // Multiply back the common factors of 2
    return a << k;
}

