long long sumofsquare(int n) {
    // Create a 2D vector filled with zeros.
    vector<vector<long long>> C(n + 1, vector<long long>(n + 1, 0));
    // Fill in the combination table.
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= min(i, n); j++) {
            if (j == 0 || j == i) {
                C[i][j] = 1;
            } else {
                C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
            }
        }
    }
    // Calculate the sum of squares of the binomial coefficients for row n.
    long long sum = 0;
    for (int i = 0; i <= n; i++) {
        sum += C[n][i] * C[n][i];
    }
    return sum;
}

