string findSum(string str1, string str2) {
    // Make sure str1 is the shorter string
    if (str1.length() > str2.length()) {
        swap(str1, str2);
    }
    string result = "";
    int n1 = str1.length(), n2 = str2.length();
    // Reverse both strings
    reverse(str1.begin(), str1.end());
    reverse(str2.begin(), str2.end());
    int carry = 0;
    // Add digits of both strings for the length of the shorter string
    for (int i = 0; i < n1; i++) {
        int sum = ((str1[i] - '0') + (str2[i] - '0') + carry);
        // Since sum is always non-negative for valid digit inputs, we use sum % 10.
        result.push_back((sum % 10) + '0');
        carry = sum / 10;
    }
    // Process remaining digits of the longer string
    for (int i = n1; i < n2; i++) {
        int sum = ((str2[i] - '0') + carry);
        result.push_back((sum % 10) + '0');
        carry = sum / 10;
    }
    // If there is any carry left, append it.
    if (carry) {
        result.push_back(carry + '0');
    }
    // Reverse the result string to restore the correct order.
    reverse(result.begin(), result.end());
    return result;
}
