unsigned int swapBits(unsigned int x, unsigned int p1, unsigned int p2, unsigned int n) {
    // Get n bits from p1 and p2 positions respectively.
    unsigned int set1 = (x >> p1) & ((1U << n) - 1);
    unsigned int set2 = (x >> p2) & ((1U << n) - 1);
    // XOR these two sets of bits.
    unsigned int xor_val = set1 ^ set2;
    // Move the xor bits back to their original positions and combine.
    xor_val = (xor_val << p1) | (xor_val << p2);
    // XOR with the original number to swap the bits.
    unsigned int result = x ^ xor_val;
    return result;
}

