long long countWays(int n) {
    // Create vectors A and B of size (n + 1) initialized with 0
    vector<long long> A(n + 1, 0);
    vector<long long> B(n + 1, 0);
    // Base cases initialization
    A[0] = 1;
    if(n >= 1) {
        A[1] = 0;
        B[0] = 0;
        B[1] = 1;
    }
    // Fill in the dynamic programming arrays
    for (int i = 2; i <= n; i++) {
        A[i] = A[i - 2] + 2 * B[i - 1];
        B[i] = A[i - 1] + B[i - 2];
    }
    return A[n];
}

