long long countTransformation(const string &a, const string &b) {
    int n = a.size();
    int m = b.size();
    if (m == 0)
        return 1;
    // Initialize dp table with dimensions m x n, all set to 0.
    vector<vector<long long>> dp(m, vector<long long>(n, 0));
    for (int i = 0; i < m; i++) {
        // j starts from i because transformation is only possible if there are at least i+1 characters
        for (int j = i; j < n; j++) {
            if (i == 0) {
                if (j == 0) {
                    dp[i][j] = (a[j] == b[i]) ? 1 : 0;
                } else {
                    if (a[j] == b[i])
                        dp[i][j] = dp[i][j - 1] + 1;
                    else
                        dp[i][j] = dp[i][j - 1];
                }
            } else {
                if (a[j] == b[i])
                    dp[i][j] = dp[i][j - 1] + dp[i - 1][j - 1];
                else
                    dp[i][j] = dp[i][j - 1];
            }
        }
    }
    // The result is stored in dp[m-1][n-1]
    return dp[m - 1][n - 1];
}
